import json
import re
import requests
from requests.exceptions import RequestException

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    # Define a regex pattern for URL validation
    url_pattern = re.compile(r'^https://[a-zA-Z0-9.-]+(?:/[\w.-]*)?$')
    
    # Check for the X-Enrich-URL header
    if 'x-enrich-url' in headers:
        enrich_urls = headers['x-enrich-url']
        
        # Validate and process each URL
        for enrich_url in enrich_urls:
            url = enrich_url['value']
            
            # Validate the URL
            if url_pattern.match(url):
                try:
                    # Fetch data from the URL
                    response = requests.get(url, timeout=5)
                    response.raise_for_status()
                    
                    # Process the response data as needed
                    # For example, add it to the request headers
                    request['headers']['x-enriched-data'] = [{'key': 'X-Enriched-Data', 'value': response.text}]
                    
                except RequestException as e:
                    # Log the error securely
                    print(f"Error fetching data from {url}: {e}")
            else:
                # Log invalid URL attempt
                print(f"Invalid URL provided: {url}")
    
    return request